(function(){let driveAccessible=!0;const logoSource='https://drive.google.com/uc?id=1dfSKTkPgHFAvW8RiIFludY6hstSshDHH';const failedMessage='Failed to connect to Google Drive. The network you are on may be blocking it. Some files/images may not be shown.';function init(){let image=new Image();image.crossOrigin='no-cors';image.onerror=()=>{console.log(failedMessage);driveAccessible=!1};image.src=logoSource}
    function before(content){init();if(!driveAccessible){return'!> '+failedMessage+'\n\n'+content}}
    const driveCheck=function(hook){hook.beforeEach(content=>{return before(content)})};$docsify.plugins=[].concat(driveCheck,$docsify.plugins)}())